def getAllPrimeFactors(n):
    if not isinstance(n, int) or n <= 0:
        return []
    if n == 1:
        return [1]
    factors = []
    while n % 2 == 0:
        factors.append(2)
        n //= 2
    i = 3
    while i * i <= n:
        while n % i == 0:
            factors.append(i)
            n //= i
        i += 2
    if n > 1:
        factors.append(n)
    return factors

def getUniquePrimeFactorsWithCount(n):
    if not isinstance(n, int) or n <= 0:
        return [[], []]
    if n == 1:
        return [[1], [1]]
    primes = []
    counts = []
    count = 0
    while n % 2 == 0:
        count += 1
        n //= 2
    if count > 0:
        primes.append(2)
        counts.append(count)
    i = 3
    while i * i <= n:
        count = 0
        while n % i == 0:
            count += 1
            n //= i
        if count > 0:
            primes.append(i)
            counts.append(count)
        i += 2
    if n > 1:
        primes.append(n)
        counts.append(1)
    return [primes, counts]

def getUniquePrimeFactorsWithProducts(n):
    if not isinstance(n, int) or n <= 0:
        return []
    if n == 1:
        return [1]
    products = []
    count = 0
    while n % 2 == 0:
        count += 1
        n //= 2
    if count > 0:
        products.append(2 ** count)
    i = 3
    while i * i <= n:
        count = 0
        while n % i == 0:
            count += 1
            n //= i
        if count > 0:
            products.append(i ** count)
        i += 2
    if n > 1:
        products.append(n)
    return products

