def calc_tip(p: int, r: int) -> int:
    # Step 1: Round p at the tens place
    rounded_p = ((p + 5) // 10) * 10

    # Step 2: Base tip T by dropping the singles place digit
    base_t = rounded_p // 10

    # Step 3: Apply rating R
    if r == 1:
        tip = base_t + 1
    elif r == 0:
        tip = base_t - 1
    else:  # r == -1
        tip = (base_t // 2) - 1

    # Ensure non-negative
    return max(0, tip)

