def min_steps(num):
    if num == 0:
        return 0  # Though constraint is 1 <= num
    q = deque([(1, 0)])
    visited = set([1])
    while q:
        cur, steps = q.popleft()
        if cur == num:
            return steps
        for next_val in [cur + 1, cur * 2]:
            if next_val <= num and next_val not in visited:
                visited.add(next_val)
                q.append((next_val, steps + 1))
    return -1  # Unreachable

