    return sign * val

def parse_pos(i, s):
    n = len(s)
    num_str = ''
    digit_start = i
    if i < n and s[i] == '-':
        num_str = '-'
        i += 1
        digit_start = i
    while i < n and s[i] in '0123456789?':
        num_str += s[i]
        i += 1
    if i == digit_start:
        return None
    return i, num_str

def solve(s):
