    i = 0
    # parse A
    res = parse_pos(i, s)
    if res is None:
        return -1
    i, A_str = res
    if i >= n or s[i] not in '+-*':
        return -1
    op = s[i]
    i += 1
    # parse B
    res = parse_pos(i, s)
    if res is None:
        return -1
    i, B_str = res
    if i >= n or s[i] != '=':
        return -1
    i += 1
    # parse C
    res = parse_pos(i, s)
    if res is None:
        return -1
    i, C_str = res
    if i != n:
        return -1
    forbidden = {c for c in s if c.isdigit()}
    num_q = s.count('?')
