def is_square(x):
    if x < 0:
        return False
    s = int(math.sqrt(x))
    return s * s == x

def sum_of_squares(n):
    # Check if n is a perfect square (1 square)
    if is_square(n):
        return 1

    # Check if n is sum of two perfect squares
    s = int(math.sqrt(n)) + 1
    for i in range(1, s):
        if is_square(n - i * i):
            return 2

    # Check if n can be expressed as sum of three squares
    # Using Legendre's three-square theorem
    m = n
    while m % 4 == 0:
        m //= 4
    if m % 8 == 7:
        return 4
    else:
        return 3

