def is_win(counts: tuple, f: int) -> bool:
    for s in range(1, 101):
        idx = s - 1
        if counts[idx] == 0:
            continue
        if s == f and counts[idx] == 1:
            continue
        # can move
        new_counts_list = list(counts)
        new_counts_list[idx] -= 1
        new_f = -1
        if s > 1:
