def build(node, ns, ne, s, tree):
    if ns == ne:
        tree[node] = s[ns]
        return
    mid = (ns + ne) // 2
    build(2 * node, ns, mid, s, tree)
    build(2 * node + 1, mid + 1, ne, s, tree)
    tree[node] = max(tree[2 * node], tree[2 * node + 1])

def query_rightmost(ql, qr, V, node, ns, ne, tree, n):
    if ql > qr or ql > ne or qr < ns:
        return -1
    if tree[node] <= V:
        return -1
    if ns == ne:
        return ns
    mid = (ns + ne) // 2
    res = query_rightmost(ql, qr, V, 2 * node + 1, mid + 1, ne, tree, n)
    if res != -1:
        return res
    return query_rightmost(ql, qr, V, 2 * node, ns, mid, tree, n)

def query_leftmost(ql, qr, V, node, ns, ne, tree, n):
    if ql > qr or ql > ne or qr < ns:
        return -1
    if tree[node] <= V:
        return -1
    if ns == ne:
        return ns
    mid = (ns + ne) // 2
    res = query_leftmost(ql, qr, V, 2 * node, ns, mid, tree, n)
    if res != -1:
        return res
    return query_leftmost(ql, qr, V, 2 * node + 1, mid + 1, ne, tree, n)

