for p, lst in exps.items():
    m = len(lst)
    z = n - m
    if z >= 2:
        continue
    lst.sort()
    if z == 0:
        e = lst[1]
    else:
        e = lst[0]
    ans *= (p ** e)

print(ans)

import sys

sys.setrecursionlimit(10**6)

MOD = 10**9 + 7

class SegTree:
    def __init__(self, size):
        self.n = size + 1
        self.tree = [0] * (4 * self.n)

    def _update(self, node, start, end, idx, val):
        if start == end:
            self.tree[node] = (self.tree[node] + val) % MOD
            return
        mid = (start + end) // 2
        if idx <= mid:
            self._update(2 * node, start, mid, idx, val)
        else:
            self._update(2 * node + 1, mid + 1, end, idx, val)
        self.tree[node] = (self.tree[2 * node] + self.tree[2 * node + 1]) % MOD

    def update(self, idx, val):
        if val == 0:
            return
        self._update(1, 0, self.n - 1, idx, val)

    def _query(self, node, start, end, l, r):
        if r < start or end < l:
            return 0
        if l <= start and end <= r:
            return self.tree[node]
        mid = (start + end) // 2
        left = self._query(2 * node, start, mid, l, r)
        right = self._query(2 * node + 1, mid + 1, end, l, r)
        return (left + right) % MOD

    def query(self, l, r):
        if l > r:
            return 0
        return self._query(1, 0, self.n - 1, l, r)

def get_hmin(suffix, target, m):
    lim = m - 1 - target
    lo = 0
    hi = target
    ans = target + 1
    while lo <= hi:
        mid = (lo + hi) // 2
        if suffix[mid] <= lim:
            ans = mid
            hi = mid - 1
        else:
            lo = mid + 1
    return ans

data = sys.stdin.read().splitlines()
line = 0
n, m = map(int, data[line].split())
line += 1
grid = data[line:line + n]

if n == 0 or m == 0:
    print(0)
    sys.exit(0)

# 0-based: rows 0 to n-1, cols 0 to m-1
suffix_row = [[0] * m for _ in range(n)]
for r in range(n):
    if m > 0:
        suffix_row[r][m - 1] = 0
    for c in range(m - 2, -1, -1):
        suffix_row[r][c] = suffix_row[r][c + 1] + (1 if grid[r][c + 1] == 'R' else 0)

suffix_col = [[0] * n for _ in range(m)]
for c in range(m):
    if n > 0:
        suffix_col[c][n - 1] = 0
    for r in range(n - 2, -1, -1):
        suffix_col[c][r] = suffix_col[c][r + 1] + (1 if grid[r + 1][c] == 'R' else 0)

hmin = [[0] * m for _ in range(n)]
for r in range(n):
    for target in range(m):
        hmin[r][target] = get_hmin(suffix_row[r], target, m)

segtrees = [SegTree(n) for _ in range(m)]

if n == 1:
    if suffix_row[0][0] <= 0:
        print(1)
    else:
        print(0)
else:
    # init row 0
    max_exit = m - 1 - suffix_row[0][0]
    for k in range(max(0, max_exit + 1)):
        snew = suffix_col[k][0]
        segtrees[k].update(snew, 1)

    for rr in range(n - 1):
        limit = n - 1 - (rr + 1)
        sum_ok = [segtrees[c].query(0, limit) for c in range(m)]
        pref = [0] * (m + 1)
        for c in range(1, m + 1):
            pref[c] = (pref[c - 1] + sum_ok[c - 1]) % MOD
        for k in range(m):
            lminn = hmin[rr + 1][k]
            if lminn > k:
                continue
            sum_end = (pref[k + 1] - pref[lminn] + MOD) % MOD
            snew = suffix_col[k][rr + 1]
            segtrees[k].update(snew, sum_end)

    # now ans for last row n-1
    ans = 0
    for L in range(m):
        ways = segtrees[L].query(0, 0)
        if suffix_row[n - 1][L] <= 0:
            ans = (ans + ways) % MOD
    print(ans)
